"use client";

import { useEffect, useMemo, useState } from "react";
import { Eye, Trash2, Check } from "lucide-react";

/** ====== sesuaikan dengan struktur row Buat Bahan Rapat kamu ====== */
type Row = {
  no: number;
  usulanId?: string;
  esl: string;
  jabatan: string;
  namaPktGolNrpNip: string;
  kondisi: string;
  calonPengisiJabatan: string;
  catatan: string;
  ket: string;
};

type BahanRapat = {
  id: string;
  tanggal: string; // yyyy-mm-dd
  materiRapat: string;
  rows: Row[];
  status: "draft" | "final";
  createdAt: string;
  updatedAt?: string;
};

const STORAGE_KEY_BAHAN_RAPAT = "bnn_bahan_rapat_v1";

/** ====== helpers localStorage ====== */
function loadBahanRapat(): BahanRapat[] {
  if (typeof window === "undefined") return [];
  try {
    const raw = localStorage.getItem(STORAGE_KEY_BAHAN_RAPAT);
    const data = raw ? (JSON.parse(raw) as BahanRapat[]) : [];
    return Array.isArray(data) ? data : [];
  } catch {
    return [];
  }
}

function saveBahanRapat(list: BahanRapat[]) {
  localStorage.setItem(STORAGE_KEY_BAHAN_RAPAT, JSON.stringify(list));
}

function fmtDate(iso: string) {
  // iso "yyyy-mm-dd" -> "dd/mm/yyyy"
  if (!iso) return "-";
  const [y, m, d] = iso.split("-");
  if (!y || !m || !d) return iso;
  return `${d}/${m}/${y}`;
}

export default function DaftarBahanRapatPage() {
  const [items, setItems] = useState<BahanRapat[]>([]);
  const [openId, setOpenId] = useState<string | null>(null);

  useEffect(() => {
    setItems(loadBahanRapat());
  }, []);

  const sorted = useMemo(() => {
    // terbaru dulu
    return [...items].sort((a, b) => (b.createdAt || "").localeCompare(a.createdAt || ""));
  }, [items]);

  const active = useMemo(() => {
    if (!openId) return null;
    return items.find((x) => x.id === openId) ?? null;
  }, [openId, items]);

  function toggleFinal(id: string) {
    const next = items.map((x) => {
      if (x.id !== id) return x;
      const toFinal = x.status !== "final";
      return {
        ...x,
        status: toFinal ? "final" : "draft",
        updatedAt: new Date().toISOString(),
      };
    });
    setItems(next);
    saveBahanRapat(next);
  }

  function onDelete(id: string) {
    const ok = confirm("Yakin mau hapus bahan rapat ini?");
    if (!ok) return;
    const next = items.filter((x) => x.id !== id);
    setItems(next);
    saveBahanRapat(next);
    if (openId === id) setOpenId(null);
  }

  return (
    <div className="px-2 py-2">
      {/* card utama (sidebar & background kamu sudah global) */}
      <div className="mx-auto w-full max-w-[1100px] rounded-md bg-white shadow-[0_14px_40px_rgba(0,0,0,0.18)] ring-1 ring-black/5">
        <div className="p-10">
          {/* header */}
          <div className="flex items-start justify-between gap-6">
            <div className="text-[11px] font-semibold text-zinc-900">
              <div>BADAN NARKOTIKA NASIONAL</div>
              <div>REPUBLIK INDONESIA</div>
              <div className="mt-2 h-[2px] w-[190px] bg-zinc-700/70" />
            </div>

            <div className="flex-1 pt-2 text-center">
              <div className="text-sm font-bold tracking-wide text-zinc-900">
                DAFTAR BAHAN RAPAT
              </div>
            </div>

            <div className="w-[190px]" />
          </div>

          {/* table */}
          <div className="mt-8 overflow-x-auto">
            <table className="w-full border border-zinc-700 text-[12px] text-zinc-900">
              <thead>
                <tr className="bg-zinc-200/80">
                  <Th className="w-[60px] text-center">NO</Th>
                  <Th className="w-[80px] text-center">ESL</Th>
                  <Th className="w-[220px] text-center">JABATAN</Th>
                  <Th className="w-[280px] text-center">
                    NAMA/PKT/GOL <br /> NRP/NIP
                  </Th>
                  <Th className="w-[220px] text-center">KONDISI</Th>
                  <Th className="w-[220px] text-center">CALON PENGISI JABATAN</Th>
                  <Th className="w-[220px] text-center">CATATAN</Th>
                  <Th className="w-[150px] text-center">KET</Th>
                  <Th className="w-[120px] text-center">STATUS</Th>
                  <Th className="w-[120px] text-center">AKSI</Th>
                </tr>
              </thead>

              <tbody>
                {sorted.length === 0 ? (
                  <tr className="border-t border-zinc-700">
                    <Td colSpan={10} className="py-10 text-center text-zinc-500">
                      Belum ada data bahan rapat. Silakan buat dulu di menu “Buat Bahan Rapat”.
                    </Td>
                  </tr>
                ) : (
                  sorted.map((doc, idx) => {
                    // mengikuti tampilan gambar: 1 dokumen = 1 baris ringkas
                    // yg ditampilkan ringkas dari row pertama (kalau ada)
                    const first = doc.rows?.[0];

                    return (
                      <tr key={doc.id} className="border-t border-zinc-700">
                        <Td className="text-center">{idx + 1}.</Td>

                        <Td className="align-top">{first?.esl || "-"}</Td>
                        <Td className="align-top whitespace-pre-wrap">{first?.jabatan || "-"}</Td>
                        <Td className="align-top whitespace-pre-wrap">{first?.namaPktGolNrpNip || "-"}</Td>
                        <Td className="align-top whitespace-pre-wrap">{first?.kondisi || "-"}</Td>
                        <Td className="align-top whitespace-pre-wrap">{first?.calonPengisiJabatan || "-"}</Td>
                        <Td className="align-top whitespace-pre-wrap">{first?.catatan || "-"}</Td>
                        <Td className="align-top whitespace-pre-wrap">{first?.ket || "-"}</Td>

                        {/* STATUS: cek bisa diklik -> FINAL */}
                        <Td className="text-center">
                          {doc.status === "final" ? (
                            <span className="inline-flex items-center rounded-md bg-emerald-50 px-2 py-1 text-[11px] font-bold text-emerald-700">
                              FINAL
                            </span>
                          ) : (
                            <button
                              type="button"
                              onClick={() => toggleFinal(doc.id)}
                              className="inline-flex items-center justify-center rounded-md border border-emerald-500/40 bg-white px-2 py-1 text-emerald-700 hover:bg-emerald-50"
                              title="Klik untuk ACC (Final)"
                            >
                              <Check size={18} />
                            </button>
                          )}

                          {/* kalau sudah final, bisa kamu biarin terkunci.
                              kalau mau bisa dibalikin draft, ganti block FINAL jadi button juga.
                          */}
                        </Td>

                        {/* AKSI */}
                        <Td className="text-center">
                          <div className="flex items-center justify-center gap-2">
                            <button
                              type="button"
                              onClick={() => setOpenId(doc.id)}
                              className="inline-flex h-9 w-9 items-center justify-center rounded-md border border-[#123473]/40 bg-white text-[#123473] shadow-sm hover:bg-[#123473]/5 active:scale-[0.98]"
                              title="Lihat"
                            >
                              <Eye size={18} />
                            </button>

                            <button
                              type="button"
                              onClick={() => onDelete(doc.id)}
                              className="inline-flex h-9 w-9 items-center justify-center rounded-md border border-red-500/40 bg-white text-red-600 shadow-sm hover:bg-red-50 active:scale-[0.98]"
                              title="Hapus"
                            >
                              <Trash2 size={18} />
                            </button>
                          </div>
                        </Td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>

          {/* footer kiri seperti gambar */}
          <div className="mt-10 text-[10px] text-zinc-700">
            <div>Birp SDM Aparatur dan Organisasi</div>
            <div>Sekretariat Utama BNN 2026</div>
          </div>
        </div>
      </div>

      {/* MODAL VIEW */}
      {active && (
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/40 p-4">
          <div className="w-full max-w-[980px] rounded-lg bg-white shadow-xl ring-1 ring-black/10">
            <div className="flex items-start justify-between gap-3 border-b px-5 py-4">
              <div>
                <div className="text-sm font-bold text-zinc-900">Detail Bahan Rapat</div>
                <div className="mt-1 text-xs text-zinc-600">
                  Tanggal: <b className="text-zinc-900">{fmtDate(active.tanggal)}</b> • Status:{" "}
                  <b className={active.status === "final" ? "text-emerald-700" : "text-zinc-900"}>
                    {active.status.toUpperCase()}
                  </b>
                </div>
              </div>

              <div className="flex items-center gap-2">
                {active.status !== "final" ? (
                  <button
                    type="button"
                    onClick={() => toggleFinal(active.id)}
                    className="rounded-md bg-emerald-600 px-3 py-2 text-xs font-semibold text-white hover:brightness-110"
                  >
                    ACC (Final)
                  </button>
                ) : null}

                <button
                  type="button"
                  onClick={() => setOpenId(null)}
                  className="rounded-md border border-zinc-300 bg-white px-3 py-2 text-xs font-semibold text-zinc-700 hover:bg-zinc-50"
                >
                  Tutup
                </button>
              </div>
            </div>

            <div className="max-h-[70vh] overflow-auto p-5">
              <div className="mb-4">
                <div className="text-xs font-semibold text-zinc-900">Materi Rapat</div>
                <div className="mt-1 whitespace-pre-wrap rounded-md border border-zinc-200 bg-zinc-50 p-3 text-xs text-zinc-800">
                  {active.materiRapat?.trim() ? active.materiRapat : "-"}
                </div>
              </div>

              <div className="overflow-x-auto">
                <table className="w-full border border-zinc-300 text-[12px] text-zinc-900">
                  <thead>
                    <tr className="bg-zinc-100">
                      <th className="border px-2 py-2 text-center">NO</th>
                      <th className="border px-2 py-2 text-center">ESL</th>
                      <th className="border px-2 py-2 text-center">JABATAN</th>
                      <th className="border px-2 py-2 text-center">NAMA/PKT/GOL/NRP-NIP</th>
                      <th className="border px-2 py-2 text-center">KONDISI</th>
                      <th className="border px-2 py-2 text-center">CALON PENGISI</th>
                      <th className="border px-2 py-2 text-center">CATATAN</th>
                      <th className="border px-2 py-2 text-center">KET</th>
                    </tr>
                  </thead>
                  <tbody>
                    {active.rows?.length ? (
                      active.rows.map((r) => (
                        <tr key={r.no} className="border-t">
                          <td className="border px-2 py-2 text-center">{r.no}</td>
                          <td className="border px-2 py-2">{r.esl || "-"}</td>
                          <td className="border px-2 py-2 whitespace-pre-wrap">{r.jabatan || "-"}</td>
                          <td className="border px-2 py-2 whitespace-pre-wrap">{r.namaPktGolNrpNip || "-"}</td>
                          <td className="border px-2 py-2 whitespace-pre-wrap">{r.kondisi || "-"}</td>
                          <td className="border px-2 py-2 whitespace-pre-wrap">{r.calonPengisiJabatan || "-"}</td>
                          <td className="border px-2 py-2 whitespace-pre-wrap">{r.catatan || "-"}</td>
                          <td className="border px-2 py-2 whitespace-pre-wrap">{r.ket || "-"}</td>
                        </tr>
                      ))
                    ) : (
                      <tr>
                        <td className="border px-3 py-6 text-center text-zinc-500" colSpan={8}>
                          Tidak ada baris data.
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>

              <div className="mt-4 text-[11px] text-zinc-500">
                Dibuat: {new Date(active.createdAt).toLocaleString()}
                {active.updatedAt ? ` • Diubah: ${new Date(active.updatedAt).toLocaleString()}` : ""}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/** ====== table components ====== */
function Th({
  children,
  className = "",
}: {
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <th className={["border border-zinc-700 px-3 py-2 font-bold", className].join(" ")}>
      {children}
    </th>
  );
}

function Td({
  children,
  className = "",
  colSpan,
}: {
  children: React.ReactNode;
  className?: string;
  colSpan?: number;
}) {
  return (
    <td colSpan={colSpan} className={["border border-zinc-700 px-2 py-2", className].join(" ")}>
      {children}
    </td>
  );
}
